/** UsptTaskPartcptsDao.insert */
insert into uspt_task_partcpts
		(
				 task_partcpts_id
				,bsns_plan_doc_id
				,partcpts_nm
				,chrg_realm_nm
				,enc_mbtlnum
				,enc_brthdy
				,partcptn_rate
				,member_id
				,creator_id
				,created_dt
				,updater_id
				,updated_dt
			) values (
				 #{taskPartcptsId}
				,#{bsnsPlanDocId}
				,#{partcptsNm}
				,#{chrgRealmNm}
				,#{encMbtlnum}
				,#{encBrthdy}
				,#{partcptnRate}
				,#{memberId}
				,#{creatorId}
				,#{createdDt}
				,#{updaterId}
				,#{updatedDt}
			)

mapper.update:
/** UsptTaskPartcptsDao.update */
update uspt_task_partcpts
	 set   partcpts_nm               = #{partcptsNm}
			,chrg_realm_nm           = #{chrgRealmNm}
			,enc_mbtlnum             = #{encMbtlnum}
			,enc_brthdy                = #{encBrthdy}
			,partcptn_rate             = #{partcptnRate}
			,member_id					= #{memberId}
			,updater_id                = #{updaterId}
			,updated_dt                = #{updatedDt}
where task_partcpts_id = #{taskPartcptsId}
  and  bsns_plan_doc_id          = #{bsnsPlanDocId}

mapper.delete:
/** UsptTaskPartcptsDao.delete */
